(function(w){"use strict";const ID="density";function compute(x){const m=Number(x.mass),v=Number(x.volume);if(!Number.isFinite(m)||!Number.isFinite(v)||v<=0)return{error:"질량과 0보다 큰 부피를 입력해 주세요."};return{value:m/v};}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>질량 (kg)</label><input class="hm-calc-input" inputmode="decimal" data-key="mass" placeholder="" value=""></div><div class="hm-calc-field"><label>부피 (m³)</label><input class="hm-calc-input" inputmode="decimal" data-key="volume" placeholder="" value=""></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=Array.prototype.slice.call(root.querySelectorAll("input[data-key]")),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const x={};inputs.forEach(i=>x[i.dataset.key]=api.parseNumber(i.value));const r=compute(x);if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("밀도",`${api.formatNumber(r.value,8)} kg/m³`,"ρ = m ÷ V"));});}
w.HM_CALC.register(ID,{compute,render});})(window);
